import React from "react";

function NumberInput({ value, onChange, ...rest }) {
  return (
    <input
      type="number"
      value={value ?? ""}
      onChange={(e) => onChange(Number(e.target.value || 0))}
      {...rest}
    />
  );
}

export default NumberInput;
